        hash: 0,
        string: 0,
        other: 0
    },
    byPattern: {
        'stream_id': 0,
        'stream_id:expire': 0,
        'aria2_gid': 0,
        'aria2_gid:expire': 0,
        'downloader_id': 0,
        'complete': 0
