};

const patterns = [
    'wis2gc:downloader:*:stream_id:*',
    'wis2gc:downloader:*:aria2_gid:*',
    'wis2gc:downloader:downloader_id:*',
    'wis2gc:downloader:complete:*'
];

const getPatternName = (key) => {
    if (key.includes(':stream_id:') && key.endsWith(':expire')) return 'stream_id:expire';
    if (key.includes(':stream_id:')) return 'stream_id';
    if (key.includes(':aria2_gid:') && key.endsWith(':expire')) return 'aria2_gid:expire';
    if (key.includes(':aria2_gid:')) return 'aria2_gid';
    if (key.includes(':downloader_id:')) return 'downloader_id';
    if (key.includes(':complete:')) return 'complete';
    return 'other';
};

const processPattern = async (pattern) => {
    const masterNodes = redis.nodes('master');

    for (const masterNode of masterNodes) {
        let cursor = '0';

        do {
            try {
                const [newCursor, keys] = await masterNode.scan(cursor, 'MATCH', pattern, 'COUNT', 100);
                cursor = newCursor;

                for (const key of keys) {
                    try {
                        const pipeline = masterNode.pipeline();
                        pipeline.ttl(key);
                        pipeline.object('IDLETIME', key);
                        pipeline.type(key);

                        const results = await pipeline.exec();

                        if (!results || results.some(r => r[0])) {
                            continue;
                        }

                        const ttl = results[0][1];
                        const idle = results[1][1];
                        const type = results[2][1];

                        if (ttl === -1 && idle > THRESHOLD) {
                            await redis.del(key);

                            stats.totalDeleted++;

                            if (type === 'hash') {
                                stats.byType.hash++;
                            } else if (type === 'string') {
                                stats.byType.string++;
                            } else {
                                stats.byType.other++;
                            }

                            const patternName = getPatternName(key);
                            if (stats.byPattern[patternName] !== undefined) {
                                stats.byPattern[patternName]++;
                            }
                        }
                    } catch (err) {
                        stats.errors++;
                    }
                }
            } catch (err) {
                node.warn(`Error scanning: ${err.message}`);
                break;
            }
        } while (cursor !== '0');
    }
};

