        String(now.getHours()).padStart(2, '0') +
        String(now.getMinutes()).padStart(2, '0') +
        String(seconds).padStart(2, '0');
}

function scheduleNext() {
    const now = new Date();
    const seconds = now.getSeconds();
    const ms = now.getMilliseconds();

    // Calculate ms until next 30-second mark
    const nextTick = ((30 - (seconds % 30)) * 1000) - ms;

    const timer = setTimeout(() => {
        // Store current timestamp in flow context
        const currentTimestamp = getTimestamp(0);
        flow.set('hashstat', currentTimestamp);

        // Send message with timestamp -30 seconds
        const previousTimestamp = getTimestamp(-30);
        node.send({ payload: previousTimestamp });

        // Schedule next update
        scheduleNext();
    }, nextTick);

    // Store timer in context so it can be cleared if needed
    context.set('timer', timer);
}

// Check if already running, if not start
if (!context.get('timer')) {
    scheduleNext();
}

