    }
}

// Extract subtopic (from 7th value onwards)
let subtopic = null;
if (output.topic) {
    const topicParts = output.topic.split('/');
    if (topicParts.length >= 6) {
        subtopic = topicParts.slice(5).join('/');  // Index 6 onwards (7th value+)
    }
}

// Add extracted values to output
output.length = length;
output.delay = delay;
output.centreId = centreId;
output.subtopic = subtopic;

