const cluster = global.get('redisCluster');

(async () => {
    try {
        const pattern = 'wis2gc:setup:*';
        const nodes = cluster.nodes('master');
        const allKeys = [];

        // Step 1: Find all matching keys across all master nodes
        for (const node of nodes) {
            let cursor = '0';
            do {
                const [newCursor, keys] = await node.scan(cursor, 'MATCH', pattern, 'COUNT', 1000);
                cursor = newCursor;
                allKeys.push(...keys);
            } while (cursor !== '0');
        }

        // node.warn(`Found ${allKeys.length} keys matching ${pattern}`);

        // Step 2: HGETALL for each key in parallel
        const promises = allKeys.map(key => 
            cluster.hgetall(key)
                .then(value => value)
                .catch(err => {
                    node.warn(`Failed to HGETALL ${key}: ${err.message}`);
                    return null;
                })
        );

        const hashResults = await Promise.all(promises);

        // Step 3: Process all hash results to extract subscriber topics
        const allTopics = [];

        for (const hashData of hashResults) {
            if (!hashData) continue; // Skip failed HGETALLs

            // hashData is an object like { "worker1:alive": "123", "worker1:subscriber": "[...]", ... }
            // We need to convert it to array format for the original logic
            const arr = [];
            for (const [key, value] of Object.entries(hashData)) {
                arr.push(key, value);
            }

            // Iterate through the array looking for *:subscriber keys
            for (let i = 0; i < arr.length; i += 2) {
                const key = arr[i];
                const value = arr[i + 1];

                // Check if key matches pattern *:subscriber
                if (key && key.endsWith(':subscriber')) {
                    try {
                        // Parse the JSON string value to array
                        const topics = JSON.parse(value);

                        // Add all topics to the collection
                        if (Array.isArray(topics)) {
                            allTopics.push(...topics);
                        }
                    } catch (e) {
                        node.warn(`Failed to parse subscriber value for ${key}: ${e.message}`);
                    }
                }
            }
        }

        // Step 4: Remove entries starting with replay/a/wis2, remove qos, and remove duplicates
        const topicsub = [...new Set(
            global.get('topic')
                .filter(item => !item.topic.startsWith('replay/a/wis2'))
                .map(item => item.topic)
        )];

        flow.set("topics", topicsub);

    } catch (err) {
        node.error('Error processing cluster data: ' + err.message);
    }
})();

return msg;
